SELECT batting_team, SUM(wickets) AS total_dismissals
FROM innings
GROUP BY batting_team;

SELECT *
FROM deliveries
WHERE ball_speed > 130;

SELECT AVG(wickets) AS average_wickets
FROM innings
WHERE match_id = 1;

SELECT * 
FROM matches 
WHERE team_a IN (
    SELECT team 
    FROM players 
    WHERE highest_score = (
        SELECT MAX(highest_score) 
        FROM players
    )
);

SELECT players.name, players.team, innings.runs
FROM players
INNER JOIN innings ON players.team = innings.batting_team;

SELECT name, team, role, date_of_birth, nationality, batting_style, bowling_style, career_start, career_end, total_matches, total_runs, total_wickets, highest_score, best_bowling, player_photo_url
FROM players
WHERE highest_score = (SELECT MAX(highest_score) FROM players);
